using Microsoft.EntityFrameworkCore;

using NexTraceOne.AIKnowledge.Application.Governance.Abstractions;
using NexTraceOne.AIKnowledge.Domain.Governance.Entities;
using NexTraceOne.AIKnowledge.Domain.Governance.Enums;

namespace NexTraceOne.AIKnowledge.Infrastructure.Governance.Persistence.Repositories;

/// <summary>
/// Additional repository implementations moved to a separate file to avoid touching
/// the large autogenerated collection of repositories in `AiGovernanceRepositories.cs`.
/// </summary>
internal sealed class PromptTemplateRepository(AiGovernanceDbContext context) : IPromptTemplateRepository
{
    public async Task<PromptTemplate?> GetByIdAsync(PromptTemplateId id, CancellationToken ct)
        => await context.PromptTemplates.SingleOrDefaultAsync(t => t.Id == id, ct);

    public async Task<PromptTemplate?> GetActiveByNameAsync(string name, CancellationToken ct)
        => await context.PromptTemplates.Where(t => t.Name == name && t.IsActive).OrderByDescending(t => t.Version).FirstOrDefaultAsync(ct);

    public async Task<IReadOnlyList<PromptTemplate>> GetAllActiveAsync(CancellationToken ct)
        => await context.PromptTemplates.Where(t => t.IsActive).OrderBy(t => t.Name).ToListAsync(ct);

    public async Task<IReadOnlyList<PromptTemplate>> GetByCategoryAsync(string category, CancellationToken ct)
        => await context.PromptTemplates.Where(t => t.Category == category).OrderBy(t => t.Name).ToListAsync(ct);

    public async Task<IReadOnlyList<PromptTemplate>> GetByPersonaAsync(string persona, CancellationToken ct)
        => await context.PromptTemplates
            .Where(t => t.TargetPersonas.Contains(persona))
            .Where(t => t.IsActive)
            .OrderBy(t => t.Name)
            .ToListAsync(ct);

    public async Task<bool> ExistsByNameAsync(string name, CancellationToken ct)
        => await context.PromptTemplates.AnyAsync(t => t.Name == name, ct);

    public async Task AddAsync(PromptTemplate entity, CancellationToken ct)
    {
        await context.PromptTemplates.AddAsync(entity, ct);
        await context.SaveChangesAsync(ct);
    }
}

internal sealed class AiGuardrailRepository(AiGovernanceDbContext context) : IAiGuardrailRepository
{
    public async Task<AiGuardrail?> GetByIdAsync(AiGuardrailId id, CancellationToken ct)
        => await context.Guardrails.SingleOrDefaultAsync(g => g.Id == id, ct);

    public async Task<AiGuardrail?> GetByNameAsync(string name, CancellationToken ct)
        => await context.Guardrails.SingleOrDefaultAsync(g => g.Name == name, ct);

    public async Task<IReadOnlyList<AiGuardrail>> GetAllActiveAsync(CancellationToken ct)
        => await context.Guardrails.Where(g => g.IsActive).OrderBy(g => g.Priority).ToListAsync(ct);

    public async Task<IReadOnlyList<AiGuardrail>> GetByCategoryAsync(string category, CancellationToken ct)
        => await context.Guardrails.Where(g => g.Category == category).OrderBy(g => g.Priority).ToListAsync(ct);

    public async Task<IReadOnlyList<AiGuardrail>> GetByGuardTypeAsync(string guardType, CancellationToken ct)
        => await context.Guardrails.Where(g => g.GuardType == guardType).OrderBy(g => g.Priority).ToListAsync(ct);

    public async Task<bool> ExistsByNameAsync(string name, CancellationToken ct)
        => await context.Guardrails.AnyAsync(g => g.Name == name, ct);

    public async Task AddAsync(AiGuardrail entity, CancellationToken ct)
    {
        await context.Guardrails.AddAsync(entity, ct);
        await context.SaveChangesAsync(ct);
    }
}

internal sealed class AiEvaluationRepository(AiGovernanceDbContext context) : IAiEvaluationRepository
{
    public async Task<AiEvaluation?> GetByIdAsync(AiEvaluationId id, CancellationToken ct)
        => await context.Evaluations.SingleOrDefaultAsync(e => e.Id == id, ct);

    public async Task<IReadOnlyList<AiEvaluation>> GetByConversationAsync(Guid conversationId, CancellationToken ct)
        => await context.Evaluations.Where(e => e.ConversationId == conversationId).OrderByDescending(e => e.CreatedAt).ToListAsync(ct);

    public async Task<IReadOnlyList<AiEvaluation>> GetByAgentExecutionAsync(Guid agentExecutionId, CancellationToken ct)
        => await context.Evaluations.Where(e => e.AgentExecutionId == agentExecutionId).OrderByDescending(e => e.CreatedAt).ToListAsync(ct);

    public async Task<IReadOnlyList<AiEvaluation>> GetByUserAsync(string userId, CancellationToken ct)
        => await context.Evaluations.Where(e => e.UserId == userId).OrderByDescending(e => e.CreatedAt).ToListAsync(ct);

    public async Task<IReadOnlyList<AiEvaluation>> GetByTenantAndPeriodAsync(Guid tenantId, DateTimeOffset start, DateTimeOffset end, CancellationToken ct)
        => await context.Evaluations.Where(e => e.TenantId == tenantId && e.CreatedAt >= start && e.CreatedAt <= end).OrderByDescending(e => e.CreatedAt).ToListAsync(ct);

    public async Task AddAsync(AiEvaluation entity, CancellationToken ct)
    {
        await context.Evaluations.AddAsync(entity, ct);
        await context.SaveChangesAsync(ct);
    }
}

internal sealed class AiFeedbackRepository(AiGovernanceDbContext context) : IAiFeedbackRepository
{
    public async Task AddAsync(AiFeedback feedback, CancellationToken ct)
    {
        await context.Feedbacks.AddAsync(feedback, ct);
        await context.SaveChangesAsync(ct);
    }

    public async Task<AiFeedback?> GetByIdAsync(AiFeedbackId id, CancellationToken ct)
        => await context.Feedbacks.SingleOrDefaultAsync(f => f.Id == id, ct);

    public async Task<IReadOnlyList<AiFeedback>> ListByConversationIdAsync(Guid conversationId, CancellationToken ct)
        => await context.Feedbacks.Where(f => f.ConversationId == conversationId).OrderByDescending(f => f.SubmittedAt).ToListAsync(ct);

    public async Task<IReadOnlyList<AiFeedback>> ListByRatingAsync(FeedbackRating rating, int limit, CancellationToken ct)
        => await context.Feedbacks.Where(f => f.Rating == rating).OrderByDescending(f => f.SubmittedAt).Take(limit).ToListAsync(ct);

    public async Task<int> CountByRatingAsync(FeedbackRating rating, CancellationToken ct)
        => await context.Feedbacks.CountAsync(f => f.Rating == rating, ct);

    public async Task<IReadOnlyList<AiFeedback>> ListByAgentNameAsync(string agentName, int limit, CancellationToken ct)
        => await context.Feedbacks.Where(f => f.AgentName == agentName).OrderByDescending(f => f.SubmittedAt).Take(limit).ToListAsync(ct);
}

internal sealed class AiToolDefinitionRepository(AiGovernanceDbContext context) : IAiToolDefinitionRepository
{
    public async Task<AiToolDefinition?> GetByIdAsync(AiToolDefinitionId id, CancellationToken ct)
        => await context.ToolDefinitions.SingleOrDefaultAsync(t => t.Id == id, ct);

    public async Task<AiToolDefinition?> GetByNameAsync(string name, CancellationToken ct)
        => await context.ToolDefinitions.SingleOrDefaultAsync(t => t.Name == name, ct);

    public async Task<IReadOnlyList<AiToolDefinition>> GetAllActiveAsync(CancellationToken ct)
        => await context.ToolDefinitions.Where(t => t.IsActive).OrderBy(t => t.Name).ToListAsync(ct);

    public async Task<IReadOnlyList<AiToolDefinition>> GetByCategoryAsync(string category, CancellationToken ct)
    {
        var query = context.ToolDefinitions.AsQueryable();

        if (!string.IsNullOrWhiteSpace(category))
            query = query.Where(t => t.Category == category);

        return await query.OrderBy(t => t.Name).ToListAsync(ct);
    }

    public async Task<bool> ExistsByNameAsync(string name, CancellationToken ct)
        => await context.ToolDefinitions.AnyAsync(t => t.Name == name, ct);

    public async Task AddAsync(AiToolDefinition entity, CancellationToken ct)
    {
        await context.ToolDefinitions.AddAsync(entity, ct);
        await context.SaveChangesAsync(ct);
    }
}
